namespace sv_5257f5a983174a00afcaba1a7992d447.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped (per-circuit) service that holds the currently selected warehouse
/// and notifies subscribers when it changes.
/// </summary>
public class WarehouseStateService
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new() { Id = "WH-A", Name = "Warehouse A" },
        new() { Id = "WH-B", Name = "Warehouse B" },
        new() { Id = "WH-C", Name = "Warehouse C" },
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    public event Func<Task>? OnChange;

    public async Task SetWarehouseAsync(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId)
            return;

        _currentWarehouseId = warehouseId;

        if (OnChange is not null)
            await OnChange.Invoke();
    }
}

namespace sv_5257f5a983174a00afcaba1a7992d447.Services;

/// <summary>
/// Scoped (per-circuit) service that polls for low-stock alerts and
/// broadcasts count changes to all subscribed components.
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly WarehouseStateService _warehouseState;
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _activePollers;

    public int CurrentAlertCount { get; private set; }

    public event Func<Task>? OnAlertCountChanged;

    public InventoryAlertService(WarehouseStateService warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnChange += HandleWarehouseChangedAsync;
    }

    /// <summary>
    /// Simulates a database query returning low-stock item count.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Starts polling. Multiple callers are ref-counted; polling runs
    /// as long as at least one caller is active.
    /// </summary>
    public void StartPolling()
    {
        _activePollers++;
        if (_activePollers == 1)
            StartTimer();
    }

    /// <summary>
    /// Stops polling for one caller. Polling truly stops when the last caller stops.
    /// </summary>
    public void StopPolling()
    {
        _activePollers = Math.Max(0, _activePollers - 1);
        if (_activePollers == 0)
            StopTimer();
    }

    private void StartTimer()
    {
        StopTimer();
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    private void StopTimer()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fetch immediately on start, then every tick.
        await FetchAndNotifyAsync();

        while (_timer is not null && !ct.IsCancellationRequested)
        {
            try
            {
                if (!await _timer.WaitForNextTickAsync(ct))
                    break;
            }
            catch (OperationCanceledException)
            {
                break;
            }

            await FetchAndNotifyAsync();
        }
    }

    private async Task FetchAndNotifyAsync()
    {
        CurrentAlertCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);

        if (OnAlertCountChanged is not null)
            await OnAlertCountChanged.Invoke();
    }

    private async Task HandleWarehouseChangedAsync()
    {
        // When the warehouse changes, immediately refresh if polling is active.
        if (_activePollers > 0)
            await FetchAndNotifyAsync();
    }

    public void Dispose()
    {
        _warehouseState.OnChange -= HandleWarehouseChangedAsync;
        StopTimer();
    }
}

