@rendermode InteractiveServer
@inject WarehouseStateService WarehouseState
@implements IDisposable

<select class="form-select form-select-sm" style="width: auto;"
        value="@WarehouseState.CurrentWarehouseId"
        @onchange="OnWarehouseChanged">
    @foreach (var wh in WarehouseStateService.AvailableWarehouses)
    {
        <option value="@wh.Id">@wh.Name</option>
    }
</select>

@code {
    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
        {
            await WarehouseState.SetWarehouseAsync(id);
            // Our own UI re-renders from the event handler return;
            // other subscribers are notified through OnChange.
        }
    }

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChangedAsync;
    }

    private async Task StateHasChangedAsync()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChangedAsync;
    }
}

@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@implements IDisposable

@if (AlertService.CurrentAlertCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto">@AlertService.CurrentAlertCount</span>
}

@code {
    protected override void OnInitialized()
    {
        AlertService.OnAlertCountChanged += OnCountChangedAsync;
    }

    private async Task OnCountChangedAsync()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= OnCountChangedAsync;
    }
}

