@rendermode InteractiveServer
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mt-3" style="max-width: 30rem;">
    <div class="card-body">
        <h5 class="card-title">@WarehouseState.CurrentWarehouseName</h5>
        <p class="card-text">
            Low-stock alerts:
            @if (AlertService.CurrentAlertCount > 0)
            {
                <span class="badge bg-danger fs-6">@AlertService.CurrentAlertCount items</span>
            }
            else
            {
                <span class="badge bg-success fs-6">All stocked</span>
            }
        </p>
        <p class="text-muted small mb-0">
            Polling every 10 seconds. Last refresh: @_lastRefresh.ToString("HH:mm:ss")
        </p>
    </div>
</div>

@code {
    private DateTime _lastRefresh = DateTime.Now;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnStateChangedAsync;
        AlertService.OnAlertCountChanged += OnAlertChangedAsync;
        AlertService.StartPolling();
    }

    private async Task OnStateChangedAsync()
    {
        await InvokeAsync(StateHasChanged);
    }

    private async Task OnAlertChangedAsync()
    {
        _lastRefresh = DateTime.Now;
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.StopPolling();
        AlertService.OnAlertCountChanged -= OnAlertChangedAsync;
        WarehouseState.OnChange -= OnStateChangedAsync;
    }
}

